import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { toast } from 'sonner';

export default function UserDashboard() {
  const [user, setUser] = useState(null);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const token = localStorage.getItem('token');
  const navigate = useNavigate();

  useEffect(() => {
    if (!token) {
      navigate('/login');
      return;
    }
    fetchData();
  }, [token, navigate]);

  const fetchData = async () => {
    try {
      // Mock session for frontend demo
      await new Promise(r => setTimeout(r, 600));
      setUser({
        email: 'dailyessentialstyle@gmail.com',
        first_name: 'DES',
        last_name: 'Customer',
        is_verified: true
      });
      setOrders([
        {
          id: 'ORD-89241',
          status: 'success',
          created_at: new Date().toISOString(),
          items: [1],
          total_amount: 145000
        }
      ]);
    } catch (err) {
      toast.error('Session expired, please login again.');
      localStorage.removeItem('token');
      navigate('/login');
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    toast.success('Logged out successfully');
    navigate('/login');
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div></div>;

  return (
    <div className="min-h-screen bg-background pt-24 pb-16">
      <div className="container mx-auto px-4 max-w-6xl">
        <div className="flex justify-between items-end mb-10 border-b border-border/50 pb-6">
          <div>
            <h1 className="text-4xl font-serif text-foreground">My Account</h1>
            <p className="text-muted-foreground mt-2">Welcome back, {user?.first_name || user?.email}!</p>
          </div>
          <button onClick={handleLogout} className="text-sm font-medium text-muted-foreground hover:text-foreground transition-colors">
            Sign out
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="md:col-span-1 space-y-6">
            <div className="bg-card p-6 rounded-2xl border border-border/50">
              <h3 className="font-serif text-xl mb-4">Profile Details</h3>
              <div className="space-y-4 text-sm text-foreground">
                <div>
                  <p className="text-muted-foreground text-xs uppercase tracking-wider mb-1">Email</p>
                  <p className="font-medium">{user.email}</p>
                </div>
                <div>
                  <p className="text-muted-foreground text-xs uppercase tracking-wider mb-1">Name</p>
                  <p className="font-medium">{user.first_name} {user.last_name}</p>
                </div>
                <div>
                  <p className="text-muted-foreground text-xs uppercase tracking-wider mb-1">Account Status</p>
                  <p className="inline-block px-2 py-1 bg-primary/10 text-primary rounded-md text-xs font-medium">
                    {user.is_verified ? 'Verified' : 'Unverified'}
                  </p>
                </div>
              </div>
            </div>
          </div>

          <div className="md:col-span-2">
            <div className="bg-card p-6 rounded-2xl border border-border/50">
               <h3 className="font-serif text-xl mb-6">Order History</h3>
               {orders.length === 0 ? (
                 <div className="text-center py-10 bg-background/50 rounded-xl border border-dashed border-border">
                   <p className="text-muted-foreground mb-4">You haven't placed any orders yet.</p>
                 </div>
               ) : (
                 <div className="space-y-4">
                   {orders.map(order => (
                     <div key={order.id} className="p-4 border border-border/50 rounded-xl flex justify-between items-center hover:bg-accent/10 transition-colors">
                       <div>
                         <p className="font-medium flex items-center gap-2">
                           Order #{order.id.split('-')[0]}
                           <span className="text-xs px-2 py-1 bg-secondary rounded-full capitalize">{order.status}</span>
                         </p>
                         <p className="text-xs text-muted-foreground mt-1">
                           {new Date(order.created_at).toLocaleDateString()} • {order.items.length} items
                         </p>
                       </div>
                       <div className="text-right">
                         <p className="font-medium">Rp {order.total_amount.toLocaleString('id-ID')}</p>
                       </div>
                     </div>
                   ))}
                 </div>
               )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
